/** Phase 9 typed guard — runtime validates StdTradingDashboardMarketFeedOrbitalParams keys. */
export function isStdTradingDashboardMarketFeedOrbitalParams(p: object): p is StdTradingDashboardMarketFeedOrbitalParams {
  type _OverrideRecord = NonNullable<StdTradingDashboardMarketFeedOrbitalParams['traitOverrides']>;
  type _SpliceRecord = NonNullable<StdTradingDashboardMarketFeedOrbitalParams['interactionStates']>;
  const obj = p as { traitOverrides?: _OverrideRecord; interactionStates?: _SpliceRecord };
  if (obj.traitOverrides !== undefined) {
    if (typeof obj.traitOverrides !== "object" || obj.traitOverrides === null) return false;
    const allowed: readonly string[] = StdTradingDashboardMarketFeedOrbitalManifest.traitNames;
    for (const k of Object.keys(obj.traitOverrides)) {
      if (!allowed.includes(k)) return false;
    }
  }
  if (obj.interactionStates !== undefined) {
    if (typeof obj.interactionStates !== "object" || obj.interactionStates === null) return false;
    const allowed: readonly string[] = StdTradingDashboardMarketFeedOrbitalManifest.inlineTraitNames;
    for (const k of Object.keys(obj.interactionStates)) {
      if (!allowed.includes(k)) return false;
    }
  }
  return true;
}

/**
 * Bundled params for std-trading-dashboard — one optional entry per orbital.
 * Each entry maps to its per-orbital factory above.
 */
export interface StdTradingDashboardParams {
  Portfolio?: StdTradingDashboardPortfolioOrbitalParams;
  TradeOrder?: StdTradingDashboardTradeOrderOrbitalParams;
  MarketFeed?: StdTradingDashboardMarketFeedOrbitalParams;
}

/** Whole-organism descriptor (3 orbitals). Composes per-orbital factories. */
export function stdTradingDashboard(params: StdTradingDashboardParams = {}): OrbitalDefinition[] {
  return [
    stdTradingDashboardPortfolioOrbital(params.Portfolio ?? {}),
    stdTradingDashboardTradeOrderOrbital(params.TradeOrder ?? {}),
    stdTradingDashboardMarketFeedOrbital(params.MarketFeed ?? {}),
  ];
}
